const item = $input.item;
const body = item.json.body || {};

// Procesamiento de la localización y datos de la alerta
return {
  json: {
    status: 'success',
    mensaje: 'Alerta procesada exitosamente en BIM-Orchestrator',
    data: {
      proyecto: body.proyecto || 'Desconocido',
      localizacion_coordenadas: body.localizacion || 'Sin coordenadas',
      elemento_afectado: body.global_id || 'N/A',
      costo_impacto: body.costo_propuesto || 0,
      nivel_criticidad: body.criticidad || 'Media',
      fecha_registro: new Date().toISOString()
    }
  }
};
